mapper.select:


left join zhs_center_project.users u on u.uuid = nt.creator
left join agent_task_developer atd on atd.task_id = nt.id
LEFT JOIN zhs_center_project.users au ON au.uuid = atd.accept
left join agent_category_link acl on acl.agent_id = nt.id
left join agent_category ac on ac.id = acl.category_id

    (atd.id is null or atd.status = 0 or atd.status = 1)
     and nt.type = #{type}
     and nt.category = #{category}
     and nt.title = #{title}
     and nt.lowest_price = #{lowestPrice}
     and nt.closing_time = #{closingTime}
     and nt.status = #{status}
     and nt.creator = #{creator}
     and nt.created_at = #{createdAt}
     and nt.reviewer = #{reviewer}
     and nt.reviewer_at = #{reviewerAt}
     and nt.invitation_code = #{invitationCode}

        and (
            nt.title like CONCAT('%', #{search}, '%')
            or nt.type like CONCAT('%', #{search}, '%')
            or u.nickname like CONCAT('%', #{search}, '%')
            or au.nickname like CONCAT('%', #{search}, '%')
            or ac.name like CONCAT('%', #{search}, '%')
        )


        and EXISTS(
            select 1 from agent_category_link cacl
            join agent_category cac on cac.id = cacl.category_id
            where cacl.agent_id = nt.id and cac.field2 = '0'

                #{typeIds}

        )


        and EXISTS(
            select 1 from agent_category_link cacl
            join agent_category cac on cac.id = cacl.category_id
            where cacl.agent_id = nt.id and cac.field2 = '1'

                #{categoryIds}

        )


order by created_at desc

