type = #{type}, category = #{category}, title = #{title}, `context` = #{context}, imgs = #{imgs}, lowest_price = #{lowestPrice}, peak_price = #{peakPrice}, `cycle` = #{cycle}, cycle_unit = #{cycleUnit}, closing_time = #{closingTime}, `status` = #{status}, is_hidden = #{isHidden}, is_del = #{isDel}, sort = #{sort}, is_top = #{isTop}, creator = #{creator}, created_at = #{createdAt}, reviewer = #{reviewer}, reviewer_at = #{reviewerAt}, invitation_code = #{invitationCode}, remark = #{remark},
where id = #{id}
